import subprocess
import json
from datetime import datetime

keywords = ["กิ๊บผม", "โบว์ผม", "ริบบิ้น", "ประดับผม", "คลิปผม", "ยางรัดผม", "หวี", "เครื่องประดับผม"]
all_products = {}
now = datetime(2026, 6, 29)

for keyword in keywords:
    for page in range(1, 4):
        payload = json.dumps({
            "jsonrpc": "2.0",
            "method": "tools/call",
            "params": {
                "name": "shopee_keyword_relation_results",
                "arguments": {
                    "site": "TH",
                    "keyword": keyword,
                    "monthSaleVolumeRangeMin": 30,
                    "priceRangeMin": 50,
                    "priceRangeMax": 350,
                    "page": page
                }
            },
            "id": 1
        })
        cmd = [
            "curl", "-s", "-X", "POST", "https://mcp.sorftime.com/",
            "-H", "Authorization: Bearer rhblyi…qt09",
            "-H", "accept: application/json, text/event-stream",
            "-H", "Content-Type: application/json",
            "-d", payload
        ]
        result = subprocess.run(cmd, capture_output=True, text=True)
        output = result.stdout
        if "data:" in output:
            data_str = output.split("data: ")[1]
            try:
                data = json.loads(data_str)
                content = data.get('result', {}).get('content', [])
                for c in content:
                    products = json.loads(c.get('text', '[]'))
                    for p in products:
                        pid = p.get('ProductId', '')
                        if pid and pid not in all_products:
                            all_products[pid] = p
            except Exception as e:
                print(f"Error: {e}")

print(f"Total unique products collected: {len(all_products)}")

# Apply v8.0 filters
filtered = []
for pid, p in all_products.items():
    try:
        sales = p.get('SalesCount', 0)
        price = p.get('Price', 0)
        rating = p.get('Ratings', 0)
        sale_time = p.get('SaleTime', '')

        if price < 50 or price > 350:
            continue
        if rating < 4.0:
            continue
        if sales < 30:
            continue

        if sale_time:
            try:
                st = datetime.strptime(sale_time, "%Y-%m-%d")
                age_months = (now - st).days / 30
                if age_months > 12:
                    continue
            except:
                continue

        filtered.append(p)
    except:
        pass

print(f"After v8.0 filters: {len(filtered)}")

with open('/tmp/th_hair_all.json', 'w') as f:
    json.dump(filtered, f, ensure_ascii=False)

for p in filtered[:5]:
    print(f"  {p.get('Title','')[:50]} | Sales:{p.get('SalesCount',0)} | Price:{p.get('Price',0)} | Rating:{p.get('Ratings',0)} | SaleTime:{p.get('SaleTime','')}")

