import subprocess
import json
from datetime import datetime

API_KEY = "***"
now = datetime(2026, 6, 29)

keywords = ["กิ๊บผม", "โบว์ผม", "ริบบิ้น", "คลิปผม", "ยางรัดผม", "หวี", "เครื่องประดับผม", "ผ้าผูกผม"]
all_products = {}

for keyword in keywords:
    for page in range(1, 3):
        payload = json.dumps({
            "jsonrpc": "2.0",
            "method": "tools/call",
            "params": {
                "name": "shopee_keyword_relation_results",
                "arguments": {
                    "site": "TH",
                    "keyword": keyword,
                    "monthSaleVolumeRangeMin": 30,
                    "priceRangeMin": 50,
                    "priceRangeMax": 350,
                    "page": page
                }
            },
            "id": page
        })

        cmd = [
            "curl", "-s", "-X", "POST", "https://mcp.sorftime.com/",
            "-H", "Authorization: Bearer " + API_KEY,
            "-H", "accept: application/json, text/event-stream",
            "-H", "Content-Type: application/json",
            "-d", payload
        ]

        try:
            result = subprocess.run(cmd, capture_output=True, text=True, timeout=20)
            output = result.stdout
            if "data:" in output:
                try:
                    data_str = output.split("data: ")[1]
                    data = json.loads(data_str)
                    content = data.get('result', {}).get('content', [])
                    for c in content:
                        text = c.get('text', '')
                        if text:
                            products = json.loads(text)
                            if isinstance(products, list):
                                for p in products:
                                    pid = p.get('ProductId', '')
                                    if pid:
                                        all_products[pid] = p
                except:
                    pass
        except:
            pass

print(f"Total: {len(all_products)}", flush=True)

filtered = []
for pid, p in all_products.items():
    try:
        sales = p.get('SalesCount', 0)
        price = p.get('Price', 0)
        rating = p.get('Ratings', 0)
        sale_time = p.get('SaleTime', '')

        if price < 50 or price > 350:
            continue
        if rating < 4.0:
            continue
        if sales < 30:
            continue
        if sale_time:
            try:
                st = datetime.strptime(sale_time, "%Y-%m-%d")
                age_months = (now - st).days / 30
                if age_months > 12:
                    continue
            except:
                pass
        filtered.append(p)
    except:
        pass

print(f"Filtered: {len(filtered)}", flush=True)

def calc_score(p):
    sales = p.get('SalesCount', 0)
    price = p.get('Price', 0)
    rating = p.get('Ratings', 0)
    sale_time = p.get('SaleTime', '')
    growth = p.get('MonthlySalesGrowth', 0)
    sales_score = min(sales / 500, 1) * 100 * 0.25
    growth_score = min(growth / 100, 1) * 100 * 0.25
    rating_score = (rating / 5.0) * 100 * 0.15
    age_score = 0
    if sale_time:
        try:
            st = datetime.strptime(sale_time, "%Y-%m-%d")
            age_months = (now - st).days / 30
            age_score = max(0, (12 - age_months) / 12) * 100 * 0.15
        except:
            pass
    price_score = 0
    if 50 <= price <= 350:
        price_score = (1 - abs(200 - price) / 300) * 100 * 0.20
    return sales_score + growth_score + rating_score + age_score + price_score

scored = [(calc_score(p), p) for p in filtered]
scored.sort(key=lambda x: x[0], reverse=True)

for i, (score, p) in enumerate(scored[:10], 1):
    title = p.get('Title', 'N/A')[:60]
    sales = p.get('SalesCount', 0)
    price = p.get('Price', 0)
    rating = p.get('Ratings', 0)
    growth = p.get('MonthlySalesGrowth', 0)
    sale_time = p.get('SaleTime', '')
    pid = p.get('ProductId', '')
    age_str = ""
    if sale_time:
        try:
            st = datetime.strptime(sale_time, "%Y-%m-%d")
            age_months = (now - st).days / 30
            age_str = f"{age_months:.1f}mo"
        except:
            age_str = "?"
    print(f"{i}|{title}|{sales}|{growth}|{price}|{rating}|{age_str}|{score:.1f}|{pid}", flush=True)

with open('/tmp/th_top10.json', 'w', encoding='utf-8') as f:
    json.dump([{"score": s, "product": p} for s, p in scored[:10]], f, ensure_ascii=False)
